function u(t){return t==null?"days-cell--positive":t<0?"days-cell--expired":t<=60?"days-cell--warning":"days-cell--positive"}function l(t){const e=new Date(t+"T00:00:00"),n=new Date(e);n.setDate(e.getDate()+6);const r=a=>a.toLocaleDateString("en-US",{month:"short",day:"numeric"});return`${r(e)} – ${r(n)}, ${e.getFullYear()}`}function c(t){return t?new Date(t).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric",timeZone:"UTC"}):"—"}function f(t,e){const n=c(t);if(!e)return n;const[r,a]=e.split(":"),o=parseInt(r,10),i=o>=12?"PM":"AM",s=o%12||12;return`${n} at ${s}:${a} ${i}`}function m(t){if(!t)return"";if(typeof t=="string")return t.includes("T")?t.split("T")[0]:t;const e=t.getFullYear(),n=String(t.getMonth()+1).padStart(2,"0"),r=String(t.getDate()).padStart(2,"0");return`${e}-${n}-${r}`}export{f as a,l as b,u as d,c as f,m as t};
